export function getSalaryData(roleSlug: string, citySlug: string): SalaryData | null {
  const cityInfo = CITIES.find(c => c.slug === citySlug)
  const roleInfo = ROLES.find(r => r.slug === roleSlug)
  if (!cityInfo || !roleInfo) return null
  const key = `${roleSlug}/${citySlug}`
  const d = SALARY_DB[key]
  if (!d) return null
  return {
    role: roleInfo.label, roleSlug,
    city: cityInfo.label, citySlug,
    state: cityInfo.state,
    median: d.median, p25: d.p25, p75: d.p75, p90: d.p90,
    yoyChange: d.yoy,
    updatedAt: 'May 2026',
  }
}

export function getAllRoleSlugs(): string[] {
  return ROLES.map(r => r.slug)
}

export function getAllCitySlugs(): string[] {
  return CITIES.map(c => c.slug)
}

export function formatSalary(amount: number): string {
  if (!amount) return 'N/A'
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(amount)
}
